sp_widget.client_script:
function CaseLookupWidgetController($scope, $http) {
    /*
     * Case Lookup Widget - client-side AngularJS controller.
     *
     * Implements the case-status-lookup user interaction described in
     * AAP Section 0.4.4 ("Page 2 - Case Status Lookup: a single input
     * (case number) and a result panel that shows status, subject,
     * opened_date when found, or the literal text 'No case found with
     * that number.' when not found.").
     *
     * Exposed properties (template-bound):
     *   c.caseNumber - string; bound to the input field via ng-model.
     *                  Initialized to '' (empty string).
     *   c.result     - object | null; on successful lookup, contains
     *                  exactly { status, subject, opened_date } - the
     *                  three whitelisted fields. null when no successful
     *                  lookup has occurred. Drives the result panel's
     *                  ng-if="c.result".
     *   c.notFound   - boolean; true when an HTTP error occurred (404,
     *                  500, 400, network error, etc.). Drives the not-
     *                  found panel's ng-if="c.notFound".
     *   c.loading    - boolean; true while the in-flight $http.get
     *                  request is pending. Drives the button's
     *                  ng-disabled and the "Looking up..." text.
     *
     * Exposed method (template-bound):
     *   c.lookup()   - executes the case-status lookup. Issues
     *                  GET /api/x_casemgmt/case_status_lookup?number=<encoded>
     *                  via $http.get(). On success (HTTP 200), sets
     *                  c.result with the strict 3-field whitelist. On
     *                  any error (HTTP 4xx/5xx, network), sets
     *                  c.notFound = true so the verbatim message is
     *                  rendered.
     *
     * Design rationale:
     *   - controller-as syntax (`var c = this`) per AAP Section 0.5.1's
     *     widget-authoring conventions and per the sibling confirmation
     *     widget at ./sp_widget_x_casemgmt_case_confirmation_widget.xml.
     *   - $http (NOT fetch): Service Portal widgets run in AngularJS
     *     1.5.x context; $http is the canonical HTTP client. fetch()
     *     would bypass AngularJS's digest cycle and require manual
     *     $scope.$apply() handling.
     *   - encodeURIComponent on the case number: defensive URL escaping.
     *     Even though normal case numbers (CASE0000001) contain no
     *     special characters, defensive encoding prevents URL-injection
     *     attacks if a malicious user submits a crafted string.
     *   - Strict 3-field whitelist on response.data: defense-in-depth.
     *     Even if the server's response somehow contained additional
     *     fields (e.g., due to a future refactor of the Script Include),
     *     this client controller extracts ONLY status/subject/opened_date
     *     so no internal data leaks to the template.
     *   - Verbatim error message in template, NOT echoed from server:
     *     the message "No case found with that number." (AAP Section
     *     0.7.4) is hardcoded in the template via ng-if="c.notFound".
     *     This controller deliberately does NOT pass error.data.error
     *     or error.statusText to the template - the server's error
     *     body is NEVER trusted by the client.
     *   - Identical handling of all HTTP errors: information-leakage
     *     hardening. 404 (not-found), 500 (server-error), 400 (bad-
     *     request), and 0 (network-error) all set c.notFound = true.
     *     An attacker cannot distinguish "case not found" from "API
     *     down" from any other failure mode.
     *   - c.loading flag: prevents double-lookup race conditions if
     *     the user clicks the button twice quickly, AND drives the
     *     "Looking up..." button text for clear UX feedback.
     */
    var c = this;

    // Lookup state. Initialize with safe defaults so the template's
    // ng-if expressions evaluate cleanly even before c.lookup() runs.
    c.caseNumber = '';
    c.result = null;
    c.notFound = false;
    c.loading = false;

    /**
     * Look up the status of a case by its number via the scripted REST
     * endpoint at /api/x_casemgmt/case_status_lookup.
     *
     * Per AAP Section 0.4.4: returns ONLY status, subject, opened_date
     * via strict 3-field whitelist on the response.
     *
     * Per AAP Section 0.7.4: on no-match (HTTP 404 or any other error),
     * the verbatim text "No case found with that number." is rendered
     * by the template. This function MUST NOT echo error.data.error or
     * any server-supplied text.
     */
    c.lookup = function() {
        // Idempotent guard: prevent double-lookup if the user clicks
        // the button or presses Enter while a request is in flight.
        if (c.loading) {
            return;
        }
        // Empty-input guard: do not issue a request if the case number
        // is empty or whitespace-only. The button is also disabled in
        // this case via ng-disabled, but the guard provides defense-
        // in-depth in case the disabled state is bypassed (e.g., by
        // pressing Enter in some edge browsers).
        if (!c.caseNumber || String(c.caseNumber).trim() === '') {
            return;
        }

        // Reset state at the start of every lookup. The result panel
        // and the not-found panel are mutually exclusive: only one of
        // c.result and c.notFound can be truthy at any time.
        c.loading = true;
        c.result = null;
        c.notFound = false;

        // Build the URL with defensive URL-encoding of the case number.
        // The server-side Script Include x_casemgmt.CasePortalService.
        // lookupCase() trims whitespace and queries by the case 'number'
        // field. encodeURIComponent() handles any whitespace, special
        // characters, or potentially malicious input safely.
        var url = '/api/x_casemgmt/case_status_lookup?number=' + encodeURIComponent(String(c.caseNumber).trim());

        $http.get(url).then(function(response) {
            // Success path (HTTP 200). The server's REST operation
            // returns { status, subject, opened_date } per its contract.
            c.loading = false;
            if (response && response.data) {
                // Strict 3-field whitelist (defense-in-depth). Extract
                // ONLY status, subject, opened_date from the response
                // body. Even if the server were misconfigured to return
                // additional fields, this widget would not display them.
                // String() coercion handles undefined/null gracefully -
                // the template renders an empty cell rather than the
                // literal text "undefined" or "null".
                c.result = {
                    status:      String(response.data.status      || ''),
                    subject:     String(response.data.subject     || ''),
                    opened_date: String(response.data.opened_date || '')
                };
                c.notFound = false;
            } else {
                // Defensive: empty response body but HTTP 200. Treat as
                // not-found rather than rendering an empty result panel.
                // This should not occur in practice (the server always
                // returns a body on 200) but guards against unexpected
                // upstream behavior.
                c.result = null;
                c.notFound = true;
            }
        }, function(error) {
            // Error path (HTTP 4xx, 5xx, or network failure / 0).
            // ALL error types are treated identically per the
            // information-leakage hardening discussed in the file
            // header comment. The verbatim text "No case found with
            // that number." (AAP Section 0.7.4) is rendered by the
            // template; this function MUST NOT echo error.data.error,
            // error.statusText, or any server-supplied content.
            c.loading = false;
            c.result = null;
            c.notFound = true;
        });
    };
}
